class Solution:
    def maximumValueSum(self, board):
        from itertools import combinations
        m, n = len(board), len(board[0])
        cells = [(board[r][c], r, c) for r in range(m) for c in range(n)]
        best = None
        for a, b, c in combinations(cells, 3):
            rows = {a[1], b[1], c[1]}
            cols = {a[2], b[2], c[2]}
            if len(rows) == 3 and len(cols) == 3:
                total = a[0] + b[0] + c[0]
                if best is None or total > best:
                    best = total
        return best

