class Solution:
    def maximumValueSum(self, board):
        m, n = len(board), len(board[0])
        row_top = []
        for r in range(m):
            row = board[r]
            idxs = sorted(range(n), key=lambda c: row[c], reverse=True)[:3]
            row_top.append([(row[c], c) for c in idxs])
        best = None
        for i in range(m):
            for j in range(i + 1, m):
                for k in range(j + 1, m):
                    for v1, c1 in row_top[i]:
                        for v2, c2 in row_top[j]:
                            if c2 == c1:
                                continue
                            for v3, c3 in row_top[k]:
                                if c3 == c1 or c3 == c2:
                                    continue
                                total = v1 + v2 + v3
                                if best is None or total > best:
                                    best = total
        return best

