var maximumValueSum = function(board) {
    const m = board.length, n = board[0].length;
    const rowTop = [];
    for (let r = 0; r < m; r++) {
        const row = board[r];
        const idxs = Array.from({ length: n }, (_, c) => c);
        idxs.sort((a, b) => row[b] - row[a]);
        rowTop.push(idxs.slice(0, 3).map(c => [row[c], c]));
    }
    let best = null;
    for (let i = 0; i < m; i++) {
        for (let j = i + 1; j < m; j++) {
            for (let k = j + 1; k < m; k++) {
                for (const [v1, c1] of rowTop[i]) {
                    for (const [v2, c2] of rowTop[j]) {
                        if (c2 === c1) continue;
                        for (const [v3, c3] of rowTop[k]) {
                            if (c3 === c1 || c3 === c2) continue;
                            const total = v1 + v2 + v3;
                            if (best === null || total > best) best = total;
                        }
                    }
                }
            }
        }
    }
    return best;
};
